arguments.new_str:
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== SOLUTION STRUCTURE ===");
build.VisitAllChildren<Project>(p => {
    Console.WriteLine($"  Project: {p.Name} | SourceFilePath: {p.SourceFilePath}");
});

Console.WriteLine("\n=== ALL ERRORS ===");
build.VisitAllChildren<Error>(e => {
    var proj = e.GetNearestParent<Project>();
    Console.WriteLine($"  [{proj?.Name ?? "unknown"}] {e.Code}: {e.Text}");
    Console.WriteLine($"    File: {e.File} Line: {e.LineNumber}");
    Console.WriteLine($"    Subcategory: {e.Subcategory}");
    Console.WriteLine();
});

Console.WriteLine("\n=== ALL WARNINGS ===");
build.VisitAllChildren<Warning>(w => {
    var proj = w.GetNearestParent<Project>();
    Console.WriteLine($"  [{proj?.Name ?? "unknown"}] {w.Code}: {w.Text}");
    Console.WriteLine($"    File: {w.File} Line: {w.LineNumber}");
    Console.WriteLine();
});

Console.WriteLine("\n=== BUILD RESULT ===");
Console.WriteLine($"  Succeeded: {build.Succeeded}");

Console.WriteLine("\n=== PROJECT DEPENDENCIES (ProjectReference) ===");
build.VisitAllChildren<Project>(p => {
    Console.WriteLine($"  Project: {p.Name}");
    p.VisitAllChildren<Item>(item => {
        if (item.Name == "ProjectReference") {
            Console.WriteLine($"    -> references: {item.Text}");
        }
    });
});

Console.WriteLine("\n=== FAILED TARGETS ===");
build.VisitAllChildren<Target>(t => {
    if (!t.Succeeded) {
        var proj = t.GetNearestParent<Project>();
        Console.WriteLine($"  [{proj?.Name ?? "unknown"}] Target '{t.Name}' FAILED");
    }
});

Console.WriteLine("\n=== SOURCE FILES (from Compile items) ===");
build.VisitAllChildren<Item>(item => {
    if (item.Name == "Compile") {
        var proj = item.GetNearestParent<Project>();
        Console.WriteLine($"  [{proj?.Name ?? "unknown"}] {item.Text}");
    }
});

