cat > /tmp/bp/Program.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Get all errors with full context
Console.WriteLine("=== ALL ERRORS (detailed) ===");
build.VisitAllChildren<Error>(e => {
    var proj = e.GetNearestParent<Project>();
    var target = e.GetNearestParent<Target>();
    var task = e.GetNearestParent<Task>();
    Console.WriteLine($"  Project: {proj?.Name}");
    Console.WriteLine($"  Target:  {target?.Name}");
    Console.WriteLine($"  Task:    {task?.Name}");
    Console.WriteLine($"  Code:    {e.Code}");
    Console.WriteLine($"  File:    {e.File}:{e.LineNumber},{e.ColumnNumber}");
    Console.WriteLine($"  Message: {e.Text}");
    Console.WriteLine();
});

// Check which projects actually reached CoreCompile
Console.WriteLine("=== CoreCompile TARGET STATUS ===");
build.VisitAllChildren<Target>(t => {
    if (t.Name == "CoreCompile") {
        var proj = t.GetNearestParent<Project>();
        Console.WriteLine($"  [{proj?.Name}] CoreCompile Succeeded={t.Succeeded}");
    }
});

// Check which projects have Build target failures
Console.WriteLine("\n=== Build TARGET STATUS ===");
build.VisitAllChildren<Target>(t => {
    if (t.Name == "Build") {
        var proj = t.GetNearestParent<Project>();
        Console.WriteLine($"  [{proj?.Name}] Build Succeeded={t.Succeeded}");
    }
});

// Check for MSB error messages
